export default function CategoryFilter() {
    return (
      <div className="w-72 bg-gray-200 rounded-md p-4">
        {/* Header */}
        <h2 className="text-sm font-semibold text-gray-700 mb-3 tracking-wide">
          CATEGORIES
        </h2>
  
        {/* All Categories */}
        <button className="w-full mb-4 py-2 text-sm font-medium bg-white rounded-lg border  hover:bg-gray-50 transition">
          All Categories
        </button>
  
        {/* Section Title */}
        <h3 className="text-sm font-semibold text-gray-800 mb-2 ps-2">
            Filter Category
        </h3>
  
        {/* Category List */}
        <div className="max-h-80 overflow-y-auto space-y-1 pr-1">
          {[
            "All",
            "Iphone",
            "Samsung",
            "Xiaomi",
            "Asus",
            "Oppo",
            "Gaming Smartphone",
            "Ipad",
            "Window Tablets",
            "eReader",
            "Smartphone Chargers",
            "5G Support Smartphone",
            "Smartphone Accessories",
            "Tablets Accessories",
            "Cell Phones",
          ].map((item, i) => (
            <label
              key={i}
              className="flex items-center justify-between px-2 py-1.5 rounded-md cursor-pointer hover:bg-white transition group"
            >
              <div className="flex items-center gap-2">
                <input
                  type="checkbox"
                  className="w-4 h-4 accent-black cursor-pointer"
                />
                <span className="text-sm text-gray-700 group-hover:text-black">
                  {item}
                </span>
              </div>
  
              {/* Price example */}
              {item === "Cell Phones" && (
                <span className="text-xs text-gray-500">$200</span>
              )}
            </label>
          ))}
        </div>
      </div>
    );
  }