export default function BrandFilter() {
    const brands = [
      { name: "envato", count: 14 },
      { name: "codecanyon", count: 6 },
      { name: "videohive", count: 7 },
      { name: "photodune", count: 18 },
      { name: "microlancer", count: 1 },
    ];
  
    return (
      <div className="w-72 bg-gray-100 rounded-2xl p-4 border border-gray-200 shadow-sm">
        
        {/* Title */}
        <h2 className="text-sm font-semibold text-gray-800 mb-4">
          By Brands
        </h2>
  
        {/* Search Input */}
        <input
          type="text"
          placeholder=""
          className="w-full mb-4 px-3 py-2 rounded-lg border border-gray-200 bg-white focus:outline-none focus:ring-1 focus:ring-gray-300"
        />
  
        {/* Brand List */}
        <div className="space-y-2">
          {brands.map((brand, i) => (
            <label
              key={i}
              className="flex items-center justify-between px-2 py-1.5 rounded-md cursor-pointer hover:bg-white transition group"
            >
              <div className="flex items-center gap-2">
                <input
                  type="checkbox"
                  className="w-4 h-4 accent-gray-700 cursor-pointer"
                />
  
                {/* Fake logo circle */}
                <div className="w-5 h-5 rounded-full bg-gray-300 flex items-center justify-center text-[10px] font-semibold text-white">
                  {brand.name.charAt(0).toUpperCase()}
                </div>
  
                <span className="text-sm text-gray-700 group-hover:text-black capitalize">
                  {brand.name}
                </span>
              </div>
  
              <span className="text-sm text-gray-400">
                ({brand.count})
              </span>
            </label>
          ))}
        </div>
      </div>
    );
  }